mapper.select:
select scId as scid, sid as sid, sNo as sno, sName as sname, scTermId as sctermid, yYear as yyear, yTerm as yterm, yAll as yall, scCourseId as sccourseid, crCode as crcode, crName as crname, scScore as scscore, scStatus as scstatus, tName as tname from vwscores where 1 = 1
and sid = #{dto.sid}
and scTermId = #{dto.termid}
and ( crName like concat('%', #{dto.qkey}, '%') or crCode like concat('%', #{dto.qkey}, '%') )
order by scTermId desc, scId desc
